&lt;%*
const activeFile = tp.config.active_file;
if (!activeFile) {
new Notice("Error: No active file found.");
return;
}
const parentMOC = activeFile.basename;
const parentFolder = activeFile.parent.path;const fileCache = app.metadataCache.getFileCache(activeFile);
const mocType = fileCache?.frontmatter?.type;let templatePath = "";
let subFolder = "";
let targetType = "";// Detection Logic
if (mocType = "project_moc") {
templatePath = "090 System/000 Templates/Project Note Template.md";
subFolder = "Logs";
targetType = "project_note";
} else if (mocType = "uni_course_moc") {
templatePath = "090 System/000 Templates/Uni Lecture Template.md";
subFolder = "Lectures";
targetType = "uni_lecture";
} else if (mocType === "course_moc") {
templatePath = "090 System/000 Templates/Course Note Template.md";
subFolder = "Lectures";
targetType = "course_note";
} else {
new Notice("Error: Active note is not a valid Course or Project MOC.");
return;
}const noteName = await tp.system.prompt("Note Name");
if (!noteName) return;// Calculate next order sequence number by counting existing files of targetType
let orderDefault = "1";
const targetFolderObj = app.vault.getAbstractFileByPath(${parentFolder}/${subFolder});
if (targetFolderObj &amp;&amp; targetFolderObj.children) {
const mdFiles = targetFolderObj.children.filter(f =&gt; {
if (f.extension !== "md" &amp;&amp; !f.name.endsWith(".md")) return false;
const cache = app.metadataCache.getFileCache(f);
return cache?.frontmatter?.type === targetType;
});
orderDefault = (mdFiles.length + 1).toString();
}const order = await tp.system.prompt("Order Number", orderDefault);const templateFile = app.vault.getAbstractFileByPath(templatePath);
if (!templateFile) {
new Notice("Error: Template file not found at " + templatePath);
return;
}
let content = await app.vault.read(templateFile);// Replacements
content = content.replace(/{{title}}/g, noteName);
content = content.replace(/{{parent}}/g, parentMOC);
content = content.replace(/{{order}}/g, order);
content = content.replace(/{{date}}/g, tp.date.now("YYYY-MM-DD"));// Create subfolder if missing
const targetPath = ${parentFolder}/${subFolder};
if (!app.vault.getAbstractFileByPath(targetPath)) {
await app.vault.createFolder(targetPath);
}// Create and Open
const finalPath = ${targetPath}/${noteName}.md;
await app.vault.create(finalPath, content);
const newFile = app.vault.getAbstractFileByPath(finalPath);
await app.workspace.getLeaf().openFile(newFile);
%&gt;

&lt;%*
const projectName = await tp.system.prompt("Project Name");
if (!projectName) return;// 1. Tag Logic
const tagsInput = await tp.system.prompt("Tags (comma separated)", "coding, security");
const tagsFormatted = tagsInput ? tagsInput.split(',').map(t =&gt; "${t.trim()}").join(", ") : "";// 2. Fetch the Template Content
const templatePath = "090 System/000 Templates/Project MOC Template.md";
const templateFile = app.vault.getAbstractFileByPath(templatePath);
if (!templateFile) {
new Notice("Error: Template file not found at " + templatePath);
return;
}
let content = await app.vault.read(templateFile);// 3. Dynamic Replacements
// This replaces placeholders in your template file with the real data
content = content.replace(/{{title}}/g, projectName);
content = content.replace(/{{tags}}/g, tagsFormatted);
content = content.replace(/{{date}}/g, tp.date.now("YYYY-MM-DD"));// 4. Folder Creation
const rootPath = 010 Projects/Todo/${projectName};
const subFolders = ["attachments", "code", "archive"];if (!app.vault.getAbstractFileByPath(rootPath)) {
await app.vault.createFolder(rootPath);
for (const sub of subFolders) {
await app.vault.createFolder(${rootPath}/${sub});
}
}// 5. Create and Open the file
const mocPath = ${rootPath}/${projectName} MOC.md;
await app.vault.create(mocPath, content);const newFile = app.vault.getAbstractFileByPath(mocPath);
await app.workspace.getLeaf().openFile(newFile);new Notice(Project ${projectName} initialized.);
%&gt;

&lt;%*
const projectName = await tp.system.prompt("University Course Name");
if (!projectName) return;// 1. Semester &amp; Academic Year Logic
const now = new Date();
const month = now.getMonth();
const year = now.getFullYear();
let semester = "";
let academicYear = "";if (month &gt;= 9 || month &lt;= 1) { // Oct (9) to Feb (1)
semester = "A";
academicYear = month &gt;= 9 ? ${year}-${year + 1} : ${year - 1}-${year};
} else if (month &gt;= 2 &amp;&amp; month &lt;= 6) { // Mar (2) to Jul (6)
semester = "B";
academicYear = ${year - 1}-${year};
} else {
semester = "Summer";
academicYear = ${year - 1}-${year};
}// 2. Fetch the Template Content
const templatePath = "090 System/000 Templates/Uni Course MOC Template.md";
const templateFile = app.vault.getAbstractFileByPath(templatePath);
if (!templateFile) {
new Notice("Error: Uni Template not found at " + templatePath);
return;
}
let content = await app.vault.read(templateFile);// 3. Dynamic Replacements
content = content.replace(/{{title}}/g, projectName);
content = content.replace(/{{semester}}/g, semester);
content = content.replace(/{{academic_year}}/g, academicYear);
content = content.replace(/{{date}}/g, tp.date.now("YYYY-MM-DD"));// 4. Folder Creation (Unified 021 University structure)
const rootPath = 021 University/${projectName};
const subFolders = ["Lectures", "Assignments", "Resources"];if (!app.vault.getAbstractFileByPath(rootPath)) {
await app.vault.createFolder(rootPath);
for (const sub of subFolders) {
await app.vault.createFolder(${rootPath}/${sub});
}
}// 5. Create and Open
const mocPath = ${rootPath}/${projectName} MOC.md;
await app.vault.create(mocPath, content);
const newFile = app.vault.getAbstractFileByPath(mocPath);
await app.workspace.getLeaf().openFile(newFile);new Notice(Enrolled in ${projectName} - Semester ${semester});
%&gt;

&lt;%*
const courseName = await tp.system.prompt("Course Name");
if (!courseName) return;const platform = await tp.system.prompt("Platform (e.g. YouTube, Coursera)", "YouTube");// 1. Fetch the Template Content
const templatePath = "090 System/000 Templates/Course MOC Template.md";
const templateFile = app.vault.getAbstractFileByPath(templatePath);
if (!templateFile) {
new Notice("Error: General Course Template not found at " + templatePath);
return;
}
let content = await app.vault.read(templateFile);// 2. Dynamic Replacements
content = content.replace(/{{title}}/g, courseName);
content = content.replace(/{{platform}}/g, platform);
content = content.replace(/{{date}}/g, tp.date.now("YYYY-MM-DD"));// 3. Folder Creation
const rootPath = 020 Courses/${courseName};
const subFolders = ["Lectures", "Assignments", "Resources"];if (!app.vault.getAbstractFileByPath(rootPath)) {
await app.vault.createFolder(rootPath);
for (const sub of subFolders) {
await app.vault.createFolder(${rootPath}/${sub});
}
}// 4. Create and Open
const mocPath = ${rootPath}/${courseName} MOC.md;
await app.vault.create(mocPath, content);
const newFile = app.vault.getAbstractFileByPath(mocPath);
await app.workspace.getLeaf().openFile(newFile);new Notice(Course ${courseName} initialized.);
%&gt;

&lt;%*
// 1. Get list of University courses (subfolders in 021 University)
const uniFolder = app.vault.getAbstractFileByPath("021 University");
if (!uniFolder || !uniFolder.children) {
new Notice("Error: 021 University folder not found.");
return;
}
const courses = uniFolder.children
.filter(c =&gt; c.children) // is a folder
.map(c =&gt; c.name)
.filter(name =&gt; name !== "Resources"); // exclude general Resources folderif (courses.length === 0) {
new Notice("No university courses found to assign homework to.");
return;
}// 2. Prompt for Course selection
const courseName = await tp.system.suggester(courses, courses);
if (!courseName) return;// 3. Prompt for Homework Name
const hwName = await tp.system.prompt("Assignment Name (e.g. Homework 1)");
if (!hwName) return;// 4. Prompt for Due Date
const dueDate = await tp.system.prompt("Due Date (YYYY-MM-DD)", tp.date.now("YYYY-MM-DD", 7));
if (!dueDate) return;// Resolve subject name and paths
const startingTime = tp.date.now("YY/MM/DD, HH:mm");
const openTag = "&lt;" + "%";
const closeTag = "%" + "&gt;";// Construct the file contents
const content = `---
type: homework
subject: "<a data-href="${courseName}" href=".html" class="internal-link" target="_self" rel="noopener nofollow">${courseName}</a>"
status: 🔴 Todo
due: ${dueDate}
tags:
Academia
links:
<br>"<a data-href="021 University/${courseName}/Assignments" href=".html" class="internal-link" target="_self" rel="noopener nofollow">021 University/${courseName}/Assignments</a>"
starting time: ${startingTime}
teacher: name
progress: WIP ${openTag} tp.file.cursor() ${closeTag}
`;// Create target folder if missing
const targetFolder = 021 University/${courseName}/Assignments;
if (!app.vault.getAbstractFileByPath(targetFolder)) {
await app.vault.createFolder(targetFolder);
}// Create and Open file
const finalPath = ${targetFolder}/${hwName}.md;
await app.vault.create(finalPath, content);const newFile = app.vault.getAbstractFileByPath(finalPath);
await app.workspace.getLeaf().openFile(newFile);new Notice(Assignment ${hwName} created.);
%&gt;

&lt;%*
const idea = await tp.system.prompt("What's the idea?");
if (!idea) return;// Clean title: first 20 chars of the idea
const cleanTitle = idea.substring(0, 20).replace(/[\/:*?"&lt;&gt;|]/g, "");
const fileName = Idea - ${cleanTitle} ${tp.date.now("HHmm")};const openTag = "&lt;" + "%";
const closeTag = "%" + "&gt;";const content = `---
type: idea_capture
status: "🧠 Raw"
date_captured: ${tp.date.now("YYYY-MM-DD HH:mm")}
tags: ["idea"]${openTag} tp.file.cursor() ${closeTag}
Convert to Project?
Convert to Permanent Note?
const path = 012 Idea Inbox/${fileName}.md;
await app.vault.create(path, content);const newFile = app.vault.getAbstractFileByPath(path);
await app.workspace.getLeaf().openFile(newFile);new Notice(Idea captured and opened from 012 Idea Inbox.);
%&gt;
